9	import { LanguageProvider } from "@/i18n/LanguageContext";
10	import { supabase } from "@/integrations/supabase/client";
11	import { useInitializeE2EE } from "@/hooks/use-initialize-e2ee";
12	import { RecoveryPasswordModal } from "@/components/auth/RecoveryPasswordModal";
13	import { SetRecoveryPasswordDialog } from "@/components/auth/SetRecoveryPasswordDialog";
14	import ScrollToTop from "./components/ScrollToTop";
15	
16	import Home from "./pages/Home";
17	import Auth from "./pages/Auth";
18	import ResetPassword from "./pages/ResetPassword";
19	import Kira from "./pages/Kira";
20	import CreviaLink from "./pages/CreviaLink";
21	import CreviaStudio from "./pages/CreviaStudio";
22	import CreviaInvoice from "./pages/CreviaInvoice";
23	import CreviaContracts from "./pages/CreviaContracts";
