41	import PublicPageWrapper from "./components/PublicPageWrapper";
42	import ProtectedRoute from "./components/auth/ProtectedRoute";
43	
44	const queryClient = new QueryClient();
45	
46	// AppContent lives inside BrowserRouter so routing hooks are available.
47	// useInitializeE2EE is called HERE — at the very top of this component,
48	// before any conditional returns — so React's rules of hooks are never violated.
49	function AppContent() {
50	  const [userId, setUserId] = useState("");
51	
52	  // MUST be called before any early returns.
53	  // Receives "" until the auth state resolves, then fires the full init flow.
54	  const {
55	    error: e2eeError,
56	    needsRecoveryPassword,
57	    needsMigration,
58	    provideRecoveryPassword,
59	    clearMigrationFlag,
60	  } = useInitializeE2EE(userId);
61	
62	  const [migrationDialogOpen, setMigrationDialogOpen] = useState(false);
63	
64	  // Open the migration dialog as soon as the flag is raised, but only once per session.
65	  useEffect(() => {
66	    if (needsMigration) setMigrationDialogOpen(true);
67	  }, [needsMigration]);
68	
69	  useEffect(() => {
70	    // onAuthStateChange fires immediately with the current session
71	    // (INITIAL_SESSION event) AND fires again on every sign-in / sign-out.
72	    // This is more reliable than getSession() which can return null on the
73	    // first tick in OAuth / server-redirect flows.
74	    const {
75	      data: { subscription },
76	    } = supabase.auth.onAuthStateChange((_event, session) => {
77	      setUserId(session?.user?.id ?? "");
78	    });
79	
80	    return () => subscription.unsubscribe();
81	  }, []);
82	
83	  return (
84	    <>
85	      <ScrollToTop />
86	
87	      {/* Non-dismissible: shown on a new device when a v2 backup exists */}
88	      <RecoveryPasswordModal
89	        open={needsRecoveryPassword}
90	        error={e2eeError}
91	        onSubmit={provideRecoveryPassword}
92	      />
93	
94	      {/* Dismissible: nudges v1 users and new users to set a recovery password */}
95	      <SetRecoveryPasswordDialog
96	        open={migrationDialogOpen}
97	        userId={userId}
98	        onOpenChange={setMigrationDialogOpen}
99	        onComplete={clearMigrationFlag}
100	      />
101	
102	      <Routes>
103	        {/* Public routes */}
104	        <Route path="/" element={<PublicPageWrapper><Home /></PublicPageWrapper>} />
105	        <Route path="/auth" element={<PublicPageWrapper><Auth /></PublicPageWrapper>} />
106	        <Route path="/reset-password" element={<PublicPageWrapper><ResetPassword /></PublicPageWrapper>} />
107	        <Route path="/pricing" element={<PublicPageWrapper><Pricing /></PublicPageWrapper>} />
108	        <Route path="/about" element={<PublicPageWrapper><About /></PublicPageWrapper>} />
109	        <Route path="/app/about" element={<AppLayout><About isEmbedded /></AppLayout>} />
110	        <Route path="/privacy-policy" element={<AppLayout><PrivacyPolicy /></AppLayout>} />
111	        <Route path="/terms-of-service" element={<AppLayout><TermsOfService /></AppLayout>} />
112	        <Route path="/user-type-selection" element={<Navigate to="/auth" replace />} />
113	        <Route path="/signup/creator" element={<Navigate to="/auth?mode=signup" replace />} />
114	        <Route path="/signup/brand" element={<Navigate to="/auth?mode=signup" replace />} />
115	        <Route path="/:username" element={<PublicPageWrapper><PublicProfile /></PublicPageWrapper>} />
116	
117	        {/* Protected routes */}
118	        <Route path="/dashboard" element={<Navigate to="/kira" replace />} />
119	        <Route path="/kira" element={<ProtectedRoute><AppLayout><Kira /></AppLayout></ProtectedRoute>} />
120	        <Route path="/crevia-link" element={<ProtectedRoute><AppLayout><CreviaLink /></AppLayout></ProtectedRoute>} />
121	        <Route path="/crevia-studio" element={<ProtectedRoute><AppLayout><CreviaStudio /></AppLayout></ProtectedRoute>} />
122	        <Route path="/crevia-invoice" element={<ProtectedRoute><AppLayout><CreviaInvoice /></AppLayout></ProtectedRoute>} />
123	        <Route path="/crevia-contracts" element={<ProtectedRoute><AppLayout><CreviaContracts /></AppLayout></ProtectedRoute>} />
124	        <Route path="/mfa-verify" element={<MFAVerify />} />
125	        <Route path="/crevia-workspace" element={<ProtectedRoute><AppLayout><WorkspacesList /></AppLayout></ProtectedRoute>} />
126	        <Route path="/crevia-workspace/:id" element={<ProtectedRoute><AppLayout><WorkspacePage /></AppLayout></ProtectedRoute>} />
127	        <Route path="/invite/:token" element={<WorkspaceInvitePage />} />
128	        <Route path="/profile/payments-billing" element={<ProtectedRoute><AppLayout><PaymentsBilling /></AppLayout></ProtectedRoute>} />
129	        <Route path="/profile/notifications" element={<ProtectedRoute><AppLayout><Notifications /></AppLayout></ProtectedRoute>} />
130	        <Route path="/profile/verification" element={<ProtectedRoute><AppLayout><Verification /></AppLayout></ProtectedRoute>} />
131	        <Route path="/profile/settings" element={<ProtectedRoute><AppLayout><Settings /></AppLayout></ProtectedRoute>} />
132	        <Route path="/profile/help" element={<ProtectedRoute><AppLayout><Help /></AppLayout></ProtectedRoute>} />
133	        <Route path="/profile/feedback" element={<ProtectedRoute><AppLayout><Feedback /></AppLayout></ProtectedRoute>} />
134	
135	        <Route path="*" element={<NotFound />} />
136	      </Routes>
137	    </>
138	  );
139	}
140	
141	const App = () => (
142	  <QueryClientProvider client={queryClient}>
143	    <ThemeProvider attribute="class" defaultTheme="light" enableSystem={false} storageKey="theme">
144	      <LanguageProvider>
145	        <TooltipProvider>
146	          <Toaster />
147	          <Sonner />
148	          <BrowserRouter>
149	            <AppContent />
150	          </BrowserRouter>
151	        </TooltipProvider>
152	      </LanguageProvider>
153	    </ThemeProvider>
154	  </QueryClientProvider>
155	);
156	
157	export default App;
