45	function timeAgo(dateStr: string): string {
46	  const diff = Date.now() - new Date(dateStr).getTime();
47	  const mins = Math.floor(diff / 60000);
48	  if (mins < 1) return "just now";
49	  if (mins < 60) return `${mins}m ago`;
50	  const hrs = Math.floor(mins / 60);
51	  if (hrs < 24) return `${hrs}h ago`;
52	  return `${Math.floor(hrs / 24)}d ago`;
53	}
54	
55	const Notifications = () => {
56	  const navigate = useNavigate();
57	  const [userId, setUserId] = useState("");
58	  const [activeId, setActiveId] = useState<string | null>(null);
59	  const [settings, setSettings] = useState<Record<string, boolean>>(() => {
60	    try {
61	      const saved = localStorage.getItem(SETTINGS_KEY);
62	      return saved ? JSON.parse(saved) : { chat: true, invoices: true, kira: true, billing: true, security: true, muteAll: false };
63	    } catch {
64	      return { chat: true, invoices: true, kira: true, billing: true, security: true, muteAll: false };
65	    }
66	  });
67	
68	  const { notifications, unreadCount, loading, markAllRead, markRead } = useNotifications(userId);
69	
70	  useEffect(() => {
71	    supabase.auth.getSession().then(({ data: { session } }) => {
72	      if (session) setUserId(session.user.id);
73	    });
74	  }, []);
75	
76	  const toggle = (id: string) => {
77	    setSettings(prev => {
78	      const next = { ...prev, [id]: !prev[id] };
79	      localStorage.setItem(SETTINGS_KEY, JSON.stringify(next));
80	      return next;
81	    });
82	  };
83	
84	  return (
85	    <div className="min-h-screen bg-background">
86	      <div className="container mx-auto px-4 md:px-6 py-8 md:py-12 max-w-2xl">
87	        <div className="flex items-center gap-3 mb-2">
88	          <Bell className="w-6 h-6 text-bronze" />
89	          <h1 className="font-vollkorn text-3xl md:text-4xl font-bold">Notifications</h1>
90	        </div>
91	        <p className="text-muted-foreground mb-8 text-sm">Manage alerts and see recent activity</p>
92	
93	        {/* Recent notifications — only shown when there are notifications */}
94	        {(loading || notifications.length > 0) && (
95	        <div className="mb-6">
96	          <div className="flex items-center justify-between mb-3">
97	            <h2 className="font-poppins text-xs font-semibold text-muted-foreground uppercase tracking-wider">
98	              Recent
99	              {unreadCount > 0 && (
100	                <span className="ml-2 px-1.5 py-0.5 rounded-full bg-bronze/10 text-bronze text-[10px]">
101	                  {unreadCount} unread
102	                </span>
103	              )}
104	            </h2>
105	            {unreadCount > 0 && (
106	              <Button variant="ghost" size="sm" className="h-7 text-xs text-bronze gap-1.5" onClick={markAllRead}>
107	                <CheckCheck className="w-3.5 h-3.5" /> Mark all read
108	              </Button>
109	            )}
110	          </div>
111	
112	          <Card className="overflow-hidden">
113	            {loading ? (
114	              <div className="flex items-center justify-center py-10">
115	                <Loader2 className="w-5 h-5 animate-spin text-muted-foreground" />
116	              </div>
117	            ) : (
118	              <div className="divide-y divide-border/50">
119	                {notifications.slice(0, 10).map(n => {
120	                  const cfg = TYPE_CONFIG[n.type] ?? TYPE_CONFIG.system;
121	                  const Icon = cfg.icon;
122	                  const isActive = activeId === n.id;
123	                  return (
124	                    <div
125	                      key={n.id}
126	                      onClick={() => {
127	                        if (!n.read) markRead(n.id);
128	                        setActiveId(n.id);
129	                        let nav = cfg.nav;
130	                        if (n.type === "message" && n.data?.room_id) {
131	                          nav = `/crevia-studio?tab=chat&roomId=${n.data.room_id}`;
132	                        }
133	                        if (nav) navigate(nav);
134	                      }}
135	                      className={cn(
136	                        "flex items-start gap-3 px-4 py-3.5 cursor-pointer hover:bg-muted/40 transition-colors",
137	                        !n.read && "bg-bronze/5",
138	                        isActive && "bg-bronze/10 border-l-2 border-bronze"
139	                      )}
140	                    >
141	                      <div className={cn("mt-0.5 p-1.5 rounded-lg flex-shrink-0", !n.read || isActive ? "bg-bronze/10" : "bg-muted")}>
142	                        <Icon className={cn("w-3.5 h-3.5", !n.read || isActive ? "text-bronze" : "text-muted-foreground")} />
143	                      </div>
144	                      <div className="flex-1 min-w-0">
145	                        <div className="flex items-start justify-between gap-2">
146	                          <p className={cn("text-sm leading-snug", !n.read || isActive ? "font-semibold" : "font-medium text-foreground/80")}>
147	                            {n.title}
148	                          </p>
149	                          {!n.read && <span className="mt-1.5 w-2 h-2 rounded-full bg-bronze flex-shrink-0" />}
150	                        </div>
151	                        {n.body && <p className="text-xs text-muted-foreground mt-0.5 line-clamp-1">{n.body}</p>}
152	                        <p className="text-[10px] text-muted-foreground/50 mt-1">{timeAgo(n.created_at)}</p>
153	                      </div>
154	                    </div>
155	                  );
156	                })}
157	              </div>
158	            )}
159	          </Card>
160	        </div>
161	        )}
162	
163	        {/* Settings */}
164	        <h2 className="font-poppins text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-3">
165	          Preferences
166	        </h2>
167	
168	        {notificationGroups.map((group) => (
169	          <Card key={group.title} className="p-5 mb-4">
170	            <h3 className="font-vollkorn text-xs font-semibold mb-4 text-muted-foreground uppercase tracking-wide">
171	              {group.title}
172	            </h3>
173	            <div className="space-y-4">
174	              {group.items.map((item) => {
175	                const Icon = item.icon;
176	                return (
177	                  <div key={item.id} className="flex items-center justify-between">
178	                    <div className="flex items-center gap-3">
179	                      <Icon className="w-4 h-4 text-bronze shrink-0" />
180	                      <div>
181	                        <Label htmlFor={item.id} className="font-medium text-sm">{item.label}</Label>
182	                        <p className="text-xs text-muted-foreground">{item.desc}</p>
183	                      </div>
184	                    </div>
185	                    <Switch
186	                      id={item.id}
187	                      checked={!settings.muteAll && settings[item.id]}
188	                      disabled={settings.muteAll}
189	                      onCheckedChange={() => toggle(item.id)}
190	                    />
191	                  </div>
192	                );
193	              })}
194	            </div>
195	          </Card>
196	        ))}
197	
198	        <Card className="p-5 border-destructive/20">
199	          <div className="flex items-center justify-between">
200	            <div className="flex items-center gap-3">
201	              <BellOff className="w-4 h-4 text-destructive shrink-0" />
202	              <div>
203	                <Label htmlFor="muteAll" className="font-medium text-sm">Mute All Notifications</Label>
204	                <p className="text-xs text-muted-foreground">Temporarily disable all alerts</p>
205	              </div>
206	            </div>
207	            <Switch id="muteAll" checked={settings.muteAll} onCheckedChange={() => toggle("muteAll")} />
208	          </div>
209	        </Card>
210	
211	      </div>
212	    </div>
213	  );
214	};
215	
216	export default Notifications;
