1	import { useEffect, useState } from "react";
2	import { Navigate } from "react-router-dom";
3	import { supabase } from "@/integrations/supabase/client";
4	
5	interface ProtectedRouteProps {
6	  children: React.ReactNode;
7	}
8	
9	const ProtectedRoute = ({ children }: ProtectedRouteProps) => {
10	  const [status, setStatus] = useState<"loading" | "auth" | "unauth">("loading");
11	
12	  useEffect(() => {
13	    // getSession() is the single authoritative initial check.
14	    // It handles token refresh internally and returns the true current state.
15	    supabase.auth.getSession().then(({ data: { session } }) => {
16	      setStatus(session ? "auth" : "unauth");
17	    });
18	
19	    // onAuthStateChange handles live transitions only.
20	    // INITIAL_SESSION is intentionally ignored to avoid racing with getSession().
21	    const { data: { subscription } } = supabase.auth.onAuthStateChange((event, session) => {
22	      if (event === "SIGNED_IN" || event === "TOKEN_REFRESHED") {
23	        setStatus("auth");
24	      } else if (event === "SIGNED_OUT") {
25	        setStatus("unauth");
26	      }
27	    });
28	
29	    return () => subscription.unsubscribe();
30	  }, []);
31	
32	  if (status === "loading") {
33	    return (
34	      <div className="min-h-screen bg-black flex items-center justify-center">
35	        <div className="text-white/60 font-poppins">Loading...</div>
36	      </div>
37	    );
38	  }
39	
40	  if (status === "unauth") {
41	    return <Navigate to="/auth" replace />;
42	  }
43	
44	  return <>{children}</>;
45	};
46	
47	export default ProtectedRoute;
